$files = Get-ChildItem "h:\souley\*.html" -Exclude "admin.html","test-menu.html"

foreach ($file in $files) {
    Write-Host "Traitement de $($file.Name)..." -ForegroundColor Yellow
    $content = Get-Content $file.FullName -Raw
    
    foreach ($icon in $iconMap.Keys) {
        $pattern = '<i data-lucide="' + $icon + '" class="([^"]+)"></i>'
        $replacement = $iconMap[$icon]
        $content = $content -replace $pattern, $replacement
    }
    
    Set-Content $file.FullName -Value $content -NoNewline
    Write-Host "  ✓ $($file.Name) mis à jour" -ForegroundColor Green
}

Write-Host ""
Write-Host "✅ Toutes les icônes ont été remplacées!" -ForegroundColor Green
